export const ADMIN_HTML = "<!doctype html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <title>HTML Sharing Admin</title>\n    <link rel=\"stylesheet\" href=\"/app.css\" />\n  </head>\n  <body>\n    <header class=\"topbar\">\n      <h1>HTML Sharing Admin</h1>\n      <div class=\"account\">\n        <span class=\"account-email\" data-account-email></span>\n        <button type=\"button\" class=\"btn\" data-signout>Sign out</button>\n      </div>\n    </header>\n\n    <main>\n      <section class=\"card\" aria-labelledby=\"upload-heading\">\n        <h2 id=\"upload-heading\">Upload a new page</h2>\n        <p class=\"hint\">\n          Give the page a title and a viewer password, then provide the HTML by choosing a file,\n          dropping it below, or pasting markup. Publishing returns a shareable link.\n        </p>\n\n        <form data-upload-form>\n          <div class=\"field-grid\">\n            <label class=\"field\">\n              <span class=\"field-label\">Title</span>\n              <input name=\"title\" type=\"text\" maxlength=\"160\" required placeholder=\"My demo page\" />\n            </label>\n            <label class=\"field\">\n              <span class=\"field-label\">Viewer password</span>\n              <input\n                name=\"password\"\n                type=\"password\"\n                minlength=\"5\"\n                maxlength=\"256\"\n                autocomplete=\"new-password\"\n                required\n              />\n            </label>\n            <label class=\"field\">\n              <span class=\"field-label\">Custom slug</span>\n              <input\n                name=\"slug\"\n                type=\"text\"\n                minlength=\"3\"\n                maxlength=\"80\"\n                pattern=\"[a-z0-9]+(-[a-z0-9]+)*\"\n                autocomplete=\"off\"\n                autocapitalize=\"none\"\n                spellcheck=\"false\"\n                placeholder=\"hello-world-test\"\n              />\n            </label>\n          </div>\n\n          <div class=\"dropzone\" data-dropzone tabindex=\"0\">\n            <p class=\"dropzone-text\">\n              Drag &amp; drop an <code>.html</code> file here, or\n              <button type=\"button\" class=\"link-btn\" data-file-trigger>choose a file</button>.\n            </p>\n            <p class=\"dropzone-file\" data-file-name hidden></p>\n            <input type=\"file\" accept=\".html,text/html\" data-file-input hidden />\n          </div>\n\n          <p class=\"or-divider\"><span>or paste HTML</span></p>\n\n          <label class=\"field\">\n            <span class=\"visually-hidden\">Paste HTML</span>\n            <textarea\n              name=\"html\"\n              rows=\"10\"\n              spellcheck=\"false\"\n              placeholder=\"&lt;!doctype html&gt;&lt;html&gt;…&lt;/html&gt;\"\n              data-html-input\n            ></textarea>\n          </label>\n\n          <p class=\"form-error\" data-upload-error hidden></p>\n\n          <div class=\"form-actions\">\n            <button type=\"submit\" class=\"btn btn-primary\" data-upload-submit>Upload &amp; publish</button>\n          </div>\n        </form>\n\n        <div class=\"copy-block\" data-upload-result hidden>\n          <p class=\"copy-block-title\">Published. Share these with your viewer:</p>\n          <pre data-result-text></pre>\n          <button type=\"button\" class=\"btn\" data-result-copy>Copy link &amp; password</button>\n        </div>\n      </section>\n\n      <section class=\"card\" aria-labelledby=\"pages-heading\">\n        <h2 id=\"pages-heading\">Your hosted pages</h2>\n        <p class=\"form-error\" data-list-error hidden></p>\n        <div class=\"table-wrap\">\n          <table>\n            <thead>\n              <tr>\n                <th>Title</th>\n                <th>Slug</th>\n                <th>Publisher</th>\n                <th>Created</th>\n                <th>Expires</th>\n                <th>Status</th>\n                <th>Password</th>\n                <th>Actions</th>\n              </tr>\n            </thead>\n            <tbody data-rows></tbody>\n          </table>\n        </div>\n        <p class=\"empty\" data-empty hidden>No pages yet.</p>\n      </section>\n    </main>\n\n    <script src=\"/app.js\" defer></script>\n  </body>\n</html>\n";

export const ADMIN_CSS = ":root {\n  color-scheme: light;\n  --bg: #f6f7f5;\n  --ink: #202124;\n  --muted: #626861;\n  --line: #dfe3dc;\n  --panel: #ffffff;\n  --accent: #146c5c;\n  --accent-ink: #ffffff;\n  --warn: #9b2f21;\n  --radius: 10px;\n}\n\n* {\n  box-sizing: border-box;\n}\n\nbody {\n  background: var(--bg);\n  color: var(--ink);\n  font-family: ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, \"Segoe UI\", sans-serif;\n  margin: 0;\n}\n\n.topbar {\n  align-items: center;\n  background: var(--panel);\n  border-bottom: 1px solid var(--line);\n  display: flex;\n  gap: 16px;\n  justify-content: space-between;\n  padding: 14px 24px;\n}\n\n.topbar h1 {\n  font-size: 20px;\n  margin: 0;\n}\n\n.account {\n  align-items: center;\n  display: flex;\n  gap: 12px;\n}\n\n.account-email {\n  color: var(--muted);\n  font-size: 13px;\n}\n\nmain {\n  display: grid;\n  gap: 20px;\n  margin: 0 auto;\n  max-width: 1180px;\n  padding: 24px;\n}\n\n.card {\n  background: var(--panel);\n  border: 1px solid var(--line);\n  border-radius: var(--radius);\n  padding: 22px 24px;\n}\n\n.card h2 {\n  font-size: 16px;\n  margin: 0 0 4px;\n}\n\n.hint {\n  color: var(--muted);\n  font-size: 13px;\n  margin: 0 0 18px;\n}\n\n.field-grid {\n  display: grid;\n  gap: 14px;\n  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));\n  margin-bottom: 16px;\n}\n\n.field {\n  display: block;\n}\n\n.field-label {\n  display: block;\n  font-size: 13px;\n  font-weight: 650;\n  margin-bottom: 6px;\n}\n\ninput,\ntextarea {\n  border: 1px solid #cbd2c8;\n  border-radius: 8px;\n  font: inherit;\n  padding: 9px 10px;\n  width: 100%;\n}\n\ntextarea {\n  font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;\n  font-size: 13px;\n  resize: vertical;\n}\n\ninput:focus,\ntextarea:focus {\n  border-color: var(--accent);\n  outline: 2px solid rgba(20, 108, 92, 0.18);\n}\n\n.dropzone {\n  border: 2px dashed #c4ccbf;\n  border-radius: var(--radius);\n  margin-bottom: 16px;\n  padding: 22px;\n  text-align: center;\n  transition: border-color 0.15s ease, background 0.15s ease;\n}\n\n.dropzone.is-dragover {\n  background: #eef4f0;\n  border-color: var(--accent);\n}\n\n.dropzone-text {\n  color: var(--muted);\n  font-size: 14px;\n  margin: 0;\n}\n\n.dropzone-file {\n  color: var(--ink);\n  font-size: 13px;\n  font-weight: 650;\n  margin: 10px 0 0;\n}\n\n.link-btn {\n  background: none;\n  border: 0;\n  color: var(--accent);\n  cursor: pointer;\n  font: inherit;\n  font-weight: 650;\n  padding: 0;\n  text-decoration: underline;\n}\n\n.or-divider {\n  color: var(--muted);\n  font-size: 12px;\n  margin: 0 0 12px;\n  overflow: hidden;\n  text-align: center;\n  text-transform: uppercase;\n  letter-spacing: 0.08em;\n}\n\n.or-divider span {\n  position: relative;\n}\n\n.or-divider span::before,\n.or-divider span::after {\n  border-top: 1px solid var(--line);\n  content: \"\";\n  position: absolute;\n  top: 50%;\n  width: 50vw;\n}\n\n.or-divider span::before {\n  right: 100%;\n  margin-right: 12px;\n}\n\n.or-divider span::after {\n  left: 100%;\n  margin-left: 12px;\n}\n\n.form-actions {\n  margin-top: 16px;\n}\n\n.btn {\n  background: #eef2ec;\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  color: var(--ink);\n  cursor: pointer;\n  font: inherit;\n  font-weight: 650;\n  padding: 8px 12px;\n}\n\n.btn:hover {\n  background: #e4ebe2;\n}\n\n.btn-primary {\n  background: var(--accent);\n  border-color: var(--accent);\n  color: var(--accent-ink);\n}\n\n.btn-primary:hover {\n  background: #115b4e;\n}\n\n.btn-danger {\n  background: #fff;\n  border-color: #e2bcb6;\n  color: var(--warn);\n}\n\n.btn-danger:hover {\n  background: #fbeeec;\n}\n\n.btn:disabled {\n  cursor: not-allowed;\n  opacity: 0.6;\n}\n\n.copy-block {\n  background: #eef4f0;\n  border: 1px solid #cfe0d7;\n  border-radius: var(--radius);\n  margin-top: 18px;\n  padding: 16px;\n}\n\n.copy-block-title {\n  font-size: 13px;\n  font-weight: 650;\n  margin: 0 0 10px;\n}\n\n.copy-block pre {\n  background: var(--panel);\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;\n  font-size: 13px;\n  margin: 0 0 12px;\n  overflow-x: auto;\n  padding: 12px;\n  white-space: pre-wrap;\n  word-break: break-all;\n}\n\n.table-wrap {\n  overflow-x: auto;\n}\n\ntable {\n  border-collapse: collapse;\n  width: 100%;\n}\n\nth,\ntd {\n  border-bottom: 1px solid var(--line);\n  font-size: 13px;\n  padding: 10px;\n  text-align: left;\n  vertical-align: middle;\n}\n\nth {\n  color: var(--muted);\n  font-weight: 650;\n}\n\ntd a {\n  color: var(--accent);\n  font-weight: 650;\n  text-decoration: none;\n}\n\ntd a:hover {\n  text-decoration: underline;\n}\n\ncode {\n  font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;\n  font-size: 12px;\n}\n\n.status {\n  border-radius: 999px;\n  display: inline-block;\n  font-size: 12px;\n  font-weight: 650;\n  padding: 2px 9px;\n}\n\n.status-active {\n  background: #e3f1ea;\n  color: #146c5c;\n}\n\n.status-expired {\n  background: #f3ead0;\n  color: #8a6d1f;\n}\n\n.status-unpublished {\n  background: #f0eceb;\n  color: var(--muted);\n}\n\n.password-cell form {\n  align-items: center;\n  display: flex;\n  gap: 6px;\n}\n\n.password-cell input {\n  max-width: 150px;\n}\n\n.actions-cell {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 6px;\n}\n\n.empty {\n  color: var(--muted);\n  padding: 18px 0;\n  text-align: center;\n}\n\n.form-error {\n  color: var(--warn);\n  font-size: 13px;\n  font-weight: 600;\n  margin: 0 0 12px;\n}\n\n.visually-hidden {\n  clip: rect(0 0 0 0);\n  clip-path: inset(50%);\n  height: 1px;\n  overflow: hidden;\n  position: absolute;\n  white-space: nowrap;\n  width: 1px;\n}\n\n@media (max-width: 760px) {\n  .field-grid {\n    grid-template-columns: 1fr;\n  }\n}\n";

export const ADMIN_JS = "\"use strict\";\n\n// Admin console client. Talks to the same-origin /api/* JSON endpoints.\n// Security: never assign untrusted strings (titles, slugs, emails) via innerHTML.\n// All preview-derived text is set with textContent / created as DOM nodes.\n(function () {\n  let csrf = \"\";\n  let previewBaseUrl = \"\";\n\n  const els = {\n    accountEmail: document.querySelector(\"[data-account-email]\"),\n    signout: document.querySelector(\"[data-signout]\"),\n    uploadForm: document.querySelector(\"[data-upload-form]\"),\n    uploadSubmit: document.querySelector(\"[data-upload-submit]\"),\n    uploadError: document.querySelector(\"[data-upload-error]\"),\n    uploadResult: document.querySelector(\"[data-upload-result]\"),\n    resultText: document.querySelector(\"[data-result-text]\"),\n    resultCopy: document.querySelector(\"[data-result-copy]\"),\n    dropzone: document.querySelector(\"[data-dropzone]\"),\n    fileTrigger: document.querySelector(\"[data-file-trigger]\"),\n    fileInput: document.querySelector(\"[data-file-input]\"),\n    fileName: document.querySelector(\"[data-file-name]\"),\n    htmlInput: document.querySelector(\"[data-html-input]\"),\n    rows: document.querySelector(\"[data-rows]\"),\n    empty: document.querySelector(\"[data-empty]\"),\n    listError: document.querySelector(\"[data-list-error]\"),\n  };\n\n  function showError(node, message) {\n    if (!node) return;\n    node.textContent = message;\n    node.hidden = false;\n  }\n\n  function clearError(node) {\n    if (!node) return;\n    node.textContent = \"\";\n    node.hidden = true;\n  }\n\n  async function readJson(response) {\n    try {\n      return await response.json();\n    } catch {\n      return null;\n    }\n  }\n\n  function apiErrorMessage(body, fallback) {\n    if (body && body.error && typeof body.error.message === \"string\") {\n      return body.error.message;\n    }\n    return fallback;\n  }\n\n  async function copyText(text) {\n    try {\n      await navigator.clipboard.writeText(text);\n      return true;\n    } catch {\n      return false;\n    }\n  }\n\n  function flashButton(button, message) {\n    if (!button) return;\n    const original = button.textContent;\n    button.textContent = message;\n    setTimeout(function () {\n      button.textContent = original;\n    }, 1400);\n  }\n\n  function shareText(url, password) {\n    return \"link: \" + url + \"\\npassword: \" + password;\n  }\n\n  function previewUrl(slug) {\n    return previewBaseUrl.replace(/\\/$/, \"\") + \"/p/\" + slug;\n  }\n\n  function formatDate(value) {\n    if (!value) return \"Never\";\n    const ts = Date.parse(value);\n    if (!Number.isFinite(ts)) return value;\n    return new Date(ts).toLocaleDateString(undefined, { year: \"numeric\", month: \"short\", day: \"numeric\" });\n  }\n\n  function statusOf(preview) {\n    if (preview.deletedAt) return \"unpublished\";\n    if (preview.expiresAt && Date.parse(preview.expiresAt) <= Date.now()) return \"expired\";\n    return \"active\";\n  }\n\n  function cell(text) {\n    const td = document.createElement(\"td\");\n    td.textContent = text == null ? \"\" : String(text);\n    return td;\n  }\n\n  function renderRow(preview) {\n    const tr = document.createElement(\"tr\");\n    const url = previewUrl(preview.slug);\n\n    const titleTd = document.createElement(\"td\");\n    const link = document.createElement(\"a\");\n    link.href = url;\n    link.target = \"_blank\";\n    link.rel = \"noopener noreferrer\";\n    link.textContent = preview.title;\n    titleTd.appendChild(link);\n    tr.appendChild(titleTd);\n\n    const slugTd = document.createElement(\"td\");\n    const code = document.createElement(\"code\");\n    code.textContent = preview.slug;\n    slugTd.appendChild(code);\n    tr.appendChild(slugTd);\n\n    tr.appendChild(cell(preview.publisherEmail));\n    tr.appendChild(cell(formatDate(preview.createdAt)));\n    tr.appendChild(cell(formatDate(preview.expiresAt)));\n\n    const status = statusOf(preview);\n    const statusTd = document.createElement(\"td\");\n    const badge = document.createElement(\"span\");\n    badge.className = \"status status-\" + status;\n    badge.textContent = status.charAt(0).toUpperCase() + status.slice(1);\n    statusTd.appendChild(badge);\n    tr.appendChild(statusTd);\n\n    // Password column: set/reset a viewer password.\n    const pwTd = document.createElement(\"td\");\n    pwTd.className = \"password-cell\";\n    const pwForm = document.createElement(\"form\");\n    const pwInput = document.createElement(\"input\");\n    pwInput.type = \"password\";\n    pwInput.placeholder = \"New password\";\n    pwInput.minLength = 5;\n    pwInput.maxLength = 256;\n    pwInput.autocomplete = \"new-password\";\n    const pwSave = document.createElement(\"button\");\n    pwSave.type = \"submit\";\n    pwSave.className = \"btn\";\n    pwSave.textContent = \"Save\";\n    pwForm.appendChild(pwInput);\n    pwForm.appendChild(pwSave);\n    pwForm.addEventListener(\"submit\", function (event) {\n      event.preventDefault();\n      resetPassword(preview, pwInput, pwSave);\n    });\n    pwTd.appendChild(pwForm);\n    tr.appendChild(pwTd);\n\n    // Actions column.\n    const actionsTd = document.createElement(\"td\");\n    const actions = document.createElement(\"div\");\n    actions.className = \"actions-cell\";\n\n    const copyBtn = document.createElement(\"button\");\n    copyBtn.type = \"button\";\n    copyBtn.className = \"btn\";\n    copyBtn.textContent = \"Copy link\";\n    copyBtn.addEventListener(\"click\", async function () {\n      const ok = await copyText(url);\n      flashButton(copyBtn, ok ? \"Copied!\" : \"Copy failed\");\n    });\n    actions.appendChild(copyBtn);\n\n    if (status !== \"unpublished\") {\n      const unpublishBtn = document.createElement(\"button\");\n      unpublishBtn.type = \"button\";\n      unpublishBtn.className = \"btn\";\n      unpublishBtn.textContent = \"Unpublish\";\n      unpublishBtn.addEventListener(\"click\", function () {\n        unpublish(preview, unpublishBtn);\n      });\n      actions.appendChild(unpublishBtn);\n    }\n\n    const deleteBtn = document.createElement(\"button\");\n    deleteBtn.type = \"button\";\n    deleteBtn.className = \"btn btn-danger\";\n    deleteBtn.textContent = \"Delete\";\n    deleteBtn.addEventListener(\"click\", function () {\n      hardDelete(preview, deleteBtn);\n    });\n    actions.appendChild(deleteBtn);\n\n    const htmlLink = document.createElement(\"a\");\n    htmlLink.className = \"btn\";\n    htmlLink.href = \"/api/previews/\" + encodeURIComponent(preview.slug) + \"/html\";\n    htmlLink.textContent = \"HTML\";\n    actions.appendChild(htmlLink);\n\n    actionsTd.appendChild(actions);\n    tr.appendChild(actionsTd);\n\n    return tr;\n  }\n\n  function renderRows(previews) {\n    els.rows.replaceChildren();\n    if (!previews.length) {\n      els.empty.hidden = false;\n      return;\n    }\n    els.empty.hidden = true;\n    const fragment = document.createDocumentFragment();\n    previews.forEach(function (preview) {\n      fragment.appendChild(renderRow(preview));\n    });\n    els.rows.appendChild(fragment);\n  }\n\n  async function loadPreviews() {\n    clearError(els.listError);\n    const response = await fetch(\"/api/previews\", { headers: { Accept: \"application/json\" } });\n    if (response.status === 401) {\n      window.location.assign(\"/login\");\n      return;\n    }\n    const body = await readJson(response);\n    if (!response.ok || !body) {\n      showError(els.listError, apiErrorMessage(body, \"Failed to load pages.\"));\n      return;\n    }\n    renderRows(Array.isArray(body.previews) ? body.previews : []);\n  }\n\n  async function postJson(url, payload) {\n    return fetch(url, {\n      method: \"POST\",\n      headers: { \"Content-Type\": \"application/json\" },\n      body: JSON.stringify(payload),\n    });\n  }\n\n  async function resetPassword(preview, input, button) {\n    const password = input.value;\n    if (password.length < 5) {\n      input.focus();\n      return;\n    }\n    button.disabled = true;\n    try {\n      const response = await postJson(\n        \"/api/previews/\" + encodeURIComponent(preview.slug) + \"/password\",\n        { csrf: csrf, password: password },\n      );\n      const body = await readJson(response);\n      if (!response.ok) {\n        flashButton(button, \"Failed\");\n        showError(els.listError, apiErrorMessage(body, \"Could not reset password.\"));\n        return;\n      }\n      input.value = \"\";\n      const ok = await copyText(shareText(previewUrl(preview.slug), password));\n      flashButton(button, ok ? \"Copied!\" : \"Saved\");\n    } finally {\n      button.disabled = false;\n    }\n  }\n\n  async function unpublish(preview, button) {\n    if (!window.confirm('Unpublish \"' + preview.title + '\"? Viewers will no longer be able to open it.')) {\n      return;\n    }\n    button.disabled = true;\n    const response = await postJson(\n      \"/api/previews/\" + encodeURIComponent(preview.slug) + \"/unpublish\",\n      { csrf: csrf },\n    );\n    if (!response.ok) {\n      const body = await readJson(response);\n      showError(els.listError, apiErrorMessage(body, \"Could not unpublish.\"));\n      button.disabled = false;\n      return;\n    }\n    await loadPreviews();\n  }\n\n  async function hardDelete(preview, button) {\n    if (!window.confirm('Permanently delete \"' + preview.title + '\"? This cannot be undone.')) {\n      return;\n    }\n    button.disabled = true;\n    const response = await postJson(\n      \"/api/previews/\" + encodeURIComponent(preview.slug) + \"/delete\",\n      { csrf: csrf, confirmSlug: preview.slug },\n    );\n    if (!response.ok) {\n      const body = await readJson(response);\n      showError(els.listError, apiErrorMessage(body, \"Could not delete.\"));\n      button.disabled = false;\n      return;\n    }\n    await loadPreviews();\n  }\n\n  function setSelectedFile(file) {\n    if (!file) return;\n    const reader = new FileReader();\n    reader.onload = function () {\n      els.htmlInput.value = typeof reader.result === \"string\" ? reader.result : \"\";\n      els.fileName.textContent = \"Loaded \" + file.name;\n      els.fileName.hidden = false;\n    };\n    reader.readAsText(file);\n  }\n\n  async function submitUpload(event) {\n    event.preventDefault();\n    clearError(els.uploadError);\n    els.uploadResult.hidden = true;\n\n    const form = els.uploadForm;\n    const title = form.elements.title.value.trim();\n    const password = form.elements.password.value;\n    const slug = form.elements.slug.value.trim();\n    const html = els.htmlInput.value;\n\n    if (!title || !password || !html.trim()) {\n      showError(els.uploadError, \"Title, password, and HTML are all required.\");\n      return;\n    }\n\n    els.uploadSubmit.disabled = true;\n    try {\n      const payload = {\n        csrf: csrf,\n        title: title,\n        password: password,\n        html: html,\n      };\n      if (slug) {\n        payload.slug = slug;\n      }\n\n      const response = await postJson(\"/api/previews\", payload);\n      const body = await readJson(response);\n      if (!response.ok || !body) {\n        showError(els.uploadError, apiErrorMessage(body, \"Upload failed.\"));\n        return;\n      }\n\n      els.resultText.textContent = shareText(body.url, password);\n      els.uploadResult.hidden = false;\n      form.reset();\n      els.htmlInput.value = \"\";\n      els.fileName.hidden = true;\n      els.fileName.textContent = \"\";\n      await loadPreviews();\n    } finally {\n      els.uploadSubmit.disabled = false;\n    }\n  }\n\n  function wireUpload() {\n    els.uploadForm.addEventListener(\"submit\", submitUpload);\n    els.fileTrigger.addEventListener(\"click\", function () {\n      els.fileInput.click();\n    });\n    els.fileInput.addEventListener(\"change\", function () {\n      setSelectedFile(els.fileInput.files && els.fileInput.files[0]);\n    });\n\n    [\"dragenter\", \"dragover\"].forEach(function (type) {\n      els.dropzone.addEventListener(type, function (event) {\n        event.preventDefault();\n        els.dropzone.classList.add(\"is-dragover\");\n      });\n    });\n    [\"dragleave\", \"dragend\", \"drop\"].forEach(function (type) {\n      els.dropzone.addEventListener(type, function (event) {\n        event.preventDefault();\n        els.dropzone.classList.remove(\"is-dragover\");\n      });\n    });\n    els.dropzone.addEventListener(\"drop\", function (event) {\n      const file = event.dataTransfer && event.dataTransfer.files && event.dataTransfer.files[0];\n      setSelectedFile(file);\n    });\n\n    els.resultCopy.addEventListener(\"click\", async function () {\n      const ok = await copyText(els.resultText.textContent || \"\");\n      flashButton(els.resultCopy, ok ? \"Copied!\" : \"Copy failed\");\n    });\n  }\n\n  function wireAccount() {\n    els.signout.addEventListener(\"click\", async function () {\n      const response = await postJson(\"/logout\", { csrf: csrf });\n      window.location.assign(response.url && response.redirected ? response.url : \"/login\");\n    });\n  }\n\n  async function init() {\n    const response = await fetch(\"/api/session\", { headers: { Accept: \"application/json\" } });\n    if (response.status === 401) {\n      window.location.assign(\"/login\");\n      return;\n    }\n    const body = await readJson(response);\n    if (!response.ok || !body) {\n      showError(els.listError, \"Could not start admin session.\");\n      return;\n    }\n    csrf = body.csrf || \"\";\n    previewBaseUrl = body.previewBaseUrl || window.location.origin;\n    if (body.user && body.user.email) {\n      els.accountEmail.textContent = body.user.email;\n    }\n    wireAccount();\n    wireUpload();\n    await loadPreviews();\n  }\n\n  init();\n})();\n";
